// an empty cell, exactly one gets filled with a 1- or 2-valued tile; if it was
// already full, every cell stays non-empty. A mutant that disables the scan
// loops leaves an all-empty input board untouched and violates this.
#define AR_SOME_NONEMPTY                                                          \
	(AR_NONEMPTY(0, 0) || AR_NONEMPTY(0, 1) || AR_NONEMPTY(0, 2) || AR_NONEMPTY(0, 3) || \
	 AR_NONEMPTY(1, 0) || AR_NONEMPTY(1, 1) || AR_NONEMPTY(1, 2) || AR_NONEMPTY(1, 3) || \
	 AR_NONEMPTY(2, 0) || AR_NONEMPTY(2, 1) || AR_NONEMPTY(2, 2) || AR_NONEMPTY(2, 3) || \
	 AR_NONEMPTY(3, 0) || AR_NONEMPTY(3, 1) || AR_NONEMPTY(3, 2) || AR_NONEMPTY(3, 3))

